// dij + 剪枝
int dis[305][60005];
struct edge {
	int to, a, b;
};
vector<edge> g[305];
struct node {
	int now, suma, sumb;
	bool operator<(const node& a)const {
		return a.sumb < sumb;
	}
};
void init() {
	fa(i, 1, 300)fa(j, 0, 60000)dis[i][j] = INF;
	return;
}
void solve(int CASE)
{
	int n, m; cin >> n >> m;
	fa(i, 1, m) {
		int u, v, a, b; cin >> u >> v >> a >> b;
		g[u].pb({ v, a, b });
	}
	var del = vector<pii>();
	var Q = priority_queue<node>();
	Q.push({ 1, 0, 0 });
	dis[1][0] = 0;
	del.pb({ 1,0 });
	ll ans = 36e8, ansa = 6e4, ansb = 6e4;
	while (Q.size()) {
		var[now, suma, sumb] = Q.top();
		Q.pop();
		if (sumb > dis[now][suma])continue;
		if (suma * 1ll * sumb > ans)continue; // 剪枝
		if (now == n) {
			ll now = suma * 1ll * sumb;
			if (now < ans) {
				ans = now;
				ansa = suma, ansb = sumb;
			}
			else if (now == ans) {
				if (suma < ansa) {
					ansa = suma, ansb = sumb;
				}
			}
			continue;
		}
		for (const var& [to, a, b] : g[now]) {
			if (suma + a > 60000)continue;
			if (dis[to][suma + a] > dis[now][suma] + b) {
				if (dis[to][suma + a] == INF)del.pb({ to, suma + a });
				dis[to][suma + a] = dis[now][suma] + b;
				Q.push({ to, suma + a, dis[to][suma + a] });
			}
		}
	}
	cout << ansa << ' ' << ansb << endl;
	for (const var& [x, y] : del)dis[x][y] = INF;
	fa(i, 1, n)g[i].clear();
	return;
}

